(window.webpackJsonp=window.webpackJsonp||[]).push([[140],{1408:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">graph</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> isBipartite = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">graph</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> N=graph.length\\n  <span class=\\"hljs-keyword\\">let</span> color=<span class=\\"hljs-built_in\\">Array</span>(N).fill(<span class=\\"hljs-literal\\">false</span>)\\n  <span class=\\"hljs-keyword\\">let</span> visited=<span class=\\"hljs-built_in\\">Array</span>(N).fill(<span class=\\"hljs-literal\\">false</span>)\\n  <span class=\\"hljs-keyword\\">let</span> valid=<span class=\\"hljs-literal\\">true</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;N;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(visited[i])<span class=\\"hljs-keyword\\">continue</span>\\n    dfs(i)\\n    <span class=\\"hljs-keyword\\">if</span>(!valid)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">v</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(!valid)<span class=\\"hljs-keyword\\">return</span>\\n    visited[v]=<span class=\\"hljs-literal\\">true</span>\\n    <span class=\\"hljs-keyword\\">let</span> adj=graph[v]\\n    <span class=\\"hljs-keyword\\">if</span>(adj){\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;adj.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(!visited[adj[i]]){\\n          color[adj[i]]=!color[v]\\n          dfs(adj[i])\\n        }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(color[adj[i]]===color[v]){\\n          <span class=\\"hljs-keyword\\">return</span> valid=<span class=\\"hljs-literal\\">false</span>\\n        }\\n      }\\n    }\\n  }\\n  \\n};\\n</code></pre>\\n"],"titleSlug":"is-graph-bipartite","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u7ecf\u5178\u7684<code>Two Color</code>\u4e0a\u8272\u95ee\u9898\uff0c<code>dfs</code>\u904d\u5386\u7ed9\u6bcf\u4e00\u4e2a\u70b9\u7684\u8fd8\u6ca1\u6709\u4e0a\u8272\u7684\u76f8\u90bb\u70b9\u4e0a\u8272\uff0c\u5982\u679c\u540e\u7eed\u53d1\u73b0\u51b2\u7a81(\u76f8\u90bb\u70b9\u989c\u8272\u76f8\u540c)\uff0c\u8fd4\u56de<code>false</code>\u3002</p>\\n<p>\u6ce8\u610f\uff1a</p>\\n<p>\u8981\u5bf9\u6bcf\u4e00\u4e2a\u70b9\u8fdb\u884c\u4e0a\u8272\u5224\u65ad(\u901a\u8fc7<code>hash</code>\u9632\u6b62\u91cd\u590d)\uff0c\u76f4\u5230\u51fa\u73b0\u51b2\u7a81\u6216\u8005\u6240\u6709\u70b9\u5224\u65ad\u5b8c\u6bd5\uff0c\u56e0\u4e3a\u53ef\u80fd\u5b58\u5728\u4e24\u4e2a\u4e0d\u76f8\u8fde\u7684\u56fe\u3002</p>\\n","content":"\u5b58\u5728\u4e00\u4e2a <strong>\u65e0\u5411\u56fe</strong> \uff0c\u56fe\u4e2d\u6709 <code>n</code> \u4e2a\u8282\u70b9\u3002\u5176\u4e2d\u6bcf\u4e2a\u8282\u70b9\u90fd\u6709\u4e00\u4e2a\u4ecb\u4e8e <code>0</code> \u5230 <code>n - 1</code> \u4e4b\u95f4\u7684\u552f\u4e00\u7f16\u53f7\u3002\u7ed9\u4f60\u4e00\u4e2a\u4e8c\u7ef4\u6570\u7ec4 <code>graph</code> \uff0c\u5176\u4e2d <code>graph[u]</code> \u662f\u4e00\u4e2a\u8282\u70b9\u6570\u7ec4\uff0c\u7531\u8282\u70b9 <code>u</code> \u7684\u90bb\u63a5\u8282\u70b9\u7ec4\u6210\u3002\u5f62\u5f0f\u4e0a\uff0c\u5bf9\u4e8e\xa0<code>graph[u]</code> \u4e2d\u7684\u6bcf\u4e2a <code>v</code> \uff0c\u90fd\u5b58\u5728\u4e00\u6761\u4f4d\u4e8e\u8282\u70b9 <code>u</code> \u548c\u8282\u70b9 <code>v</code> \u4e4b\u95f4\u7684\u65e0\u5411\u8fb9\u3002\u8be5\u65e0\u5411\u56fe\u540c\u65f6\u5177\u6709\u4ee5\u4e0b\u5c5e\u6027\uff1a\\n<ul>\\n\\t<li>\u4e0d\u5b58\u5728\u81ea\u73af\uff08<code>graph[u]</code> \u4e0d\u5305\u542b <code>u</code>\uff09\u3002</li>\\n\\t<li>\u4e0d\u5b58\u5728\u5e73\u884c\u8fb9\uff08<code>graph[u]</code> \u4e0d\u5305\u542b\u91cd\u590d\u503c\uff09\u3002</li>\\n\\t<li>\u5982\u679c <code>v</code> \u5728 <code>graph[u]</code> \u5185\uff0c\u90a3\u4e48 <code>u</code> \u4e5f\u5e94\u8be5\u5728 <code>graph[v]</code> \u5185\uff08\u8be5\u56fe\u662f\u65e0\u5411\u56fe\uff09</li>\\n\\t<li>\u8fd9\u4e2a\u56fe\u53ef\u80fd\u4e0d\u662f\u8fde\u901a\u56fe\uff0c\u4e5f\u5c31\u662f\u8bf4\u4e24\u4e2a\u8282\u70b9 <code>u</code> \u548c <code>v</code> \u4e4b\u95f4\u53ef\u80fd\u4e0d\u5b58\u5728\u4e00\u6761\u8fde\u901a\u5f7c\u6b64\u7684\u8def\u5f84\u3002</li>\\n</ul>\\n\\n<p><strong>\u4e8c\u5206\u56fe</strong> \u5b9a\u4e49\uff1a\u5982\u679c\u80fd\u5c06\u4e00\u4e2a\u56fe\u7684\u8282\u70b9\u96c6\u5408\u5206\u5272\u6210\u4e24\u4e2a\u72ec\u7acb\u7684\u5b50\u96c6 <code>A</code> \u548c <code>B</code> \uff0c\u5e76\u4f7f\u56fe\u4e2d\u7684\u6bcf\u4e00\u6761\u8fb9\u7684\u4e24\u4e2a\u8282\u70b9\u4e00\u4e2a\u6765\u81ea <code>A</code> \u96c6\u5408\uff0c\u4e00\u4e2a\u6765\u81ea <code>B</code> \u96c6\u5408\uff0c\u5c31\u5c06\u8fd9\u4e2a\u56fe\u79f0\u4e3a <strong>\u4e8c\u5206\u56fe</strong> \u3002</p>\\n\\n<p>\u5982\u679c\u56fe\u662f\u4e8c\u5206\u56fe\uff0c\u8fd4\u56de <code>true</code><em> </em>\uff1b\u5426\u5219\uff0c\u8fd4\u56de <code>false</code> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/10/21/bi2.jpg\\" style=\\"width: 222px; height: 222px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>graph = [[1,2,3],[0,2],[0,1,3],[0,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n<strong>\u89e3\u91ca\uff1a</strong><code>\u4e0d\u80fd\u5c06\u8282\u70b9\u5206\u5272\u6210\u4e24\u4e2a\u72ec\u7acb\u7684\u5b50\u96c6\uff0c</code>\u4ee5\u4f7f\u6bcf\u6761\u8fb9\u90fd\u8fde\u901a\u4e00\u4e2a\u5b50\u96c6\u4e2d\u7684\u4e00\u4e2a\u8282\u70b9\u4e0e\u53e6\u4e00\u4e2a\u5b50\u96c6\u4e2d\u7684\u4e00\u4e2a\u8282\u70b9\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/10/21/bi1.jpg\\" style=\\"width: 222px; height: 222px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>graph = [[1,3],[0,2],[1,3],[0,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong><code>\u53ef\u4ee5\u5c06\u8282\u70b9\u5206\u6210\u4e24\u7ec4: {0, 2} \u548c {1, 3} \u3002</code></pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>graph.length == n</code></li>\\n\\t<li><code>1 <= n <= 100</code></li>\\n\\t<li><code>0 <= graph[u].length < n</code></li>\\n\\t<li><code>0 <= graph[u][i] <= n - 1</code></li>\\n\\t<li><code>graph[u]</code> \u4e0d\u4f1a\u5305\u542b <code>u</code></li>\\n\\t<li><code>graph[u]</code> \u7684\u6240\u6709\u503c <strong>\u4e92\u4e0d\u76f8\u540c</strong></li>\\n\\t<li>\u5982\u679c <code>graph[u]</code> \u5305\u542b <code>v</code>\uff0c\u90a3\u4e48 <code>graph[v]</code> \u4e5f\u4f1a\u5305\u542b <code>u</code></li>\\n</ul>\\n","title":"785. \u5224\u65ad\u4e8c\u5206\u56fe","relatedTags":["\u6df1\u5ea6\u4f18\u5148\u641c\u7d22","\u5e7f\u5ea6\u4f18\u5148\u641c\u7d22","\u56fe"],"difficult":"Middle","lang":["javascript"],"uniqueID":"785"}')}}]);